const incoming = $input.first().json;

const body =
  incoming.body ||
  incoming;

const plan =
  body.implementationPlan ||
  body.plan ||
  {};

const rawName =
  plan.featureName ||
  body.featureName ||
  'unnamed-feature';

const featureName = rawName
  .toLowerCase()
  .replace(/\s+/g, '-')
  .replace(/[^a-z0-9-]/g, '');

const tmpRoot = '/tmp';
const timestamp = Date.now();
const workDir = `${tmpRoot}/logitruck-${featureName}-${timestamp}`;

return [
  {
    json: {
      debugIncomingKeys: Object.keys(incoming),
      debugBodyKeys: Object.keys(body),
      debugPlanKeys: Object.keys(plan),

      project: body.project || 'LogiTruck',
      featureName,
      featureArchetype: plan.featureArchetype || '',
      repoUrl: body.repoUrl || '',
      baseBranch: body.baseBranch || plan.branch || 'main',
      workDir,
      repoDir: `${workDir}/repo`,
      handoffPath: `${workDir}/handoff`,
      plan,
      riskLevel: plan.architectureImpact?.riskLevel || 'low',
      executionLevel: '',
      model: '',
      testsData: { tests: [] },
      implData: { files: [] },
      testsWritten: [],
      filesWritten: [],
      validationOutput: '',
      validationPassed: false,
      status: 'parsed',
      errors: []
    }
  }
];

const data = $input.first().json;
if (data.status === 'rejected') return [{ json: data }];
const plan = data.plan;
const required = ['featureName','featureArchetype','businessIntent','repoContext','architectureImpact','automationScope','files','testingStrategy','factoryExecutionPlan','acceptanceCriteria'];
const validArchetypes = ['utility-feature','mobile-screen-feature','firestore-feature','cloud-function-feature','maps-tracking-feature','native-integration-feature','payments-stripe-connect-feature','ai-support-agent-feature','voice-agent-elevenlabs-feature','landing-react-vite-feature'];
const errors = [];
required.filter(f => !plan[f]).forEach(f => errors.push('Missing required field: ' + f));
if (!validArchetypes.includes(plan.featureArchetype)) errors.push('Invalid featureArchetype: ' + plan.featureArchetype);
if ((!plan.files || (!plan.files.create || !plan.files.create.length)) && (!plan.files || (!plan.files.modify || !plan.files.modify.length))) errors.push('files.create or files.modify must have at least one entry');
if (!plan.testingStrategy || !plan.testingStrategy.commands || !plan.testingStrategy.commands.length) errors.push('testingStrategy.commands must not be empty');
if (errors.length > 0) return [{ json: { ...data, status: 'rejected', errors } }];
return [{ json: { ...data, status: 'validated' } }];

const data = $input.first().json;
const plan = data.plan;
const archetype = plan.featureArchetype;
const risk = (plan.architectureImpact && plan.architectureImpact.riskLevel) || 'low';
const nativeRisk = plan.architectureImpact && plan.architectureImpact.nativeRisk === true;
const levelMap = {
  'utility-feature': 'L0',
  'landing-react-vite-feature': 'L0',
  'mobile-screen-feature': 'L1',
  'ai-support-agent-feature': 'L1',
  'firestore-feature': (risk === 'high' || risk === 'critical') ? 'L2' : 'L1',
  'cloud-function-feature': risk === 'critical' ? 'L2' : 'L1',
  'maps-tracking-feature': nativeRisk ? 'L2' : 'L1',
  'native-integration-feature': 'L2',
  'payments-stripe-connect-feature': 'L2',
  'voice-agent-elevenlabs-feature': 'L2'
};
const executionLevel = levelMap[archetype] || 'L2';
const model = executionLevel === 'L0' ? 'claude-haiku-4-5-20251001' : 'claude-sonnet-4-6';
const maxRetries = (plan.factoryExecutionPlan && plan.factoryExecutionPlan.maxRetries != null) ? plan.factoryExecutionPlan.maxRetries : 2;
return [{ json: { ...data, executionLevel, riskLevel: risk, model, maxRetries, status: 'classified' } }];

const cmd = $input.first().json;
const data = $('Classify Risk').first().json;
if (cmd.exitCode !== 0) {
  return [{ json: { ...data, status: 'error', errors: [...data.errors, 'Setup sandbox failed: ' + cmd.stderr] } }];
}
return [{ json: { ...data, status: 'sandbox_ready' } }];

const cmd = $input.first().json;
const data = $('After Setup Sandbox').first().json;
if (cmd.exitCode !== 0) {
  return [{ json: { ...data, status: 'error', errors: [...data.errors, 'Clone failed: ' + cmd.stderr] } }];
}
return [{ json: { ...data, status: 'cloned' } }];

const fs = require('fs');
const path = require('path');

const data = $input.first().json;
const plan = data.plan;
const repoDir = data.repoDir;

function safeRead(relativePath) {
  const fullPath = path.join(repoDir, relativePath);
  try {
    if (!fs.existsSync(fullPath)) return `FILE_NOT_FOUND: ${relativePath}`;
    return fs.readFileSync(fullPath, 'utf8');
  } catch (e) {
    return `ERROR_READING_FILE: ${relativePath}\n${e.message}`;
  }
}

function readJson(relativePath) {
  try {
    return JSON.parse(safeRead(relativePath));
  } catch {
    return {};
  }
}

function normalizeBlockName(block) {
  if (!block) return null;
  if (typeof block === 'string') return block.replace(/\.md$/, '');

  const raw = block.name || block.file || block.path;
  if (!raw) return null;

  return String(raw).split('/').pop().replace(/\.md$/, '');
}

const registry = readJson('factory/registry/archetype-registry.json');

const archetypeConfig =
  registry[plan.featureArchetype] ||
  registry.archetypes?.[plan.featureArchetype] ||
  {};

const defaultBlocks =
  archetypeConfig.defaultBuildingBlocks || [];

const selectedBlocks =
  plan.selectedBuildingBlocks || [];

const resolvedBuildingBlocks = [
  ...new Set([
    ...defaultBlocks.map(normalizeBlockName),
    ...selectedBlocks.map(normalizeBlockName)
  ].filter(Boolean))
];

const buildingBlockContents = resolvedBuildingBlocks.map(blockName => {
  const relativePath = `factory/building-blocks/${blockName}.md`;

  return [
    `# BUILDING BLOCK: ${blockName}`,
    `# SOURCE: ${relativePath}`,
    safeRead(relativePath)
  ].join('\n\n');
});

const archetypePath = `factory/archetypes/${plan.featureArchetype}.md`;

const contextBundle = [
  `# IMPLEMENTATION PLAN\n${JSON.stringify(plan, null, 2)}`,

  `# RESOLVED BUILDING BLOCKS\n${resolvedBuildingBlocks.join('\n')}`,

  `# FACTORY CLAUDE RULES\n${safeRead('factory/CLAUDE.md')}`,

  `# FACTORY ARCHITECTURE\n${safeRead('factory/ARCHITECTURE.md')}`,

  `# ARCHETYPE\n# SOURCE: ${archetypePath}\n${safeRead(archetypePath)}`,

  `# ARCHETYPE REGISTRY\n${JSON.stringify(archetypeConfig, null, 2)}`,

  `# EXECUTION REGISTRY\n${safeRead('factory/registry/execution-registry.md')}`,

  `# BUILDING BLOCK RESOLUTION\n${safeRead('factory/registry/BUILDING_BLOCK_RESOLUTION.md')}`,

  `# GRAPHIFY REPORT\n${safeRead('graphify-out/GRAPH_REPORT.md')}`,

  `# FIRESTORE DATA MODEL REGISTRY\n${safeRead('factory/registry/data-model-registry.json')}`,

`# PROJECT STRUCTURE REGISTRY\n${safeRead('factory/registry/project-structure-registry.json')}`,

  ...buildingBlockContents
].join('\n\n---\n\n');

return [{
  json: {
    ...data,
    plan: {
      ...plan,
      resolvedBuildingBlocks
    },
    contextBundle,
    loadedBuildingBlocks: resolvedBuildingBlocks,
    status: 'context_loaded'
  }
}];

const data = $input.first().json;
const plan = data.plan;

const acceptanceCriteria = (plan.acceptanceCriteria || [])
  .map(c => '- ' + c)
  .join('\n');

const patterns = (plan.repoContext?.existingPatternsToFollow || [])
  .join('\n');

const filesToCreate = JSON.stringify(plan.files?.create || [], null, 2);
const testingStrategy = JSON.stringify(plan.testingStrategy || {}, null, 2);
const contextBundle = data.contextBundle || '';

const llmPrompt =
`You are the LogiTruck Factory test generator.

Return ONLY valid JSON.
Do not use markdown.
Do not use code fences.
Do not explain anything.
Do not wrap the response in "output".
Return the root object directly.
Valid root keys:
- tests

Generate Jest tests for this feature.

IMPLEMENTATION PLAN:
${JSON.stringify(plan, null, 2)}

FILES TO CREATE:
${filesToCreate}

TESTING STRATEGY:
${testingStrategy}

ACCEPTANCE CRITERIA:
${acceptanceCriteria}

EXISTING PATTERNS:
${patterns}

LOGITRUCK FACTORY CONTEXT:
${contextBundle}

TEST SCOPE:
1. unauthenticated user throws HttpsError unauthenticated
2. missing vendorID throws HttpsError invalid-argument
3. returns active trucks for vendorID
4. maps Firestore docs correctly
5. Firestore errors throw internal error

CRITICAL SIZE LIMIT:
- Generate only ONE test file.
- Generate maximum 5 test cases.
- Keep the decoded test file under 150 lines.
- Do not test every edge case.
- Focus only on acceptance criteria.
- Do not include long boilerplate.
- Use concise mocks.

RULES:
- Pure utilities: import directly, no renderHook, no React Testing Library.
- React hooks: use renderHook from @testing-library/react-native.
- Tests must FAIL before implementation exists and PASS after implementation.
- No real Firebase/Stripe/OpenAI/ElevenLabs calls — use jest.mock().
- Test edge cases and error paths.
- Use describe/it blocks with clear readable names.
- Encode the full test file content as base64.
- Do not return raw file content.
- The decoded content must be valid TypeScript/Jest code.

Output exactly this JSON shape:
{
  "tests": [
    {
      "filePath": "src/utils/__tests__/example.test.ts",
      "contentBase64": "base64 encoded full test file content"
    }
  ]
}`;

return [
  {
    json: {
      ...data,
      llmPrompt,
      status: 'test_prompt_built'
    }
  }
];

const response = $input.first().json;
const data = $('Load Context Bundle').first().json;

try {

  const source =
    response.output ||
    response;

  let tests = {
    tests: source.tests || []
  };

  tests.tests = tests.tests.map(test => ({
    ...test,
    content:
      test.content ||
      Buffer.from(
        test.contentBase64 || '',
        'base64'
      ).toString('utf8')
  }));

  return [
    {
      json: {
        ...data,
        testsData: tests,
        status: 'tests_generated'
      }
    }
  ];

} catch (e) {

  return [
    {
      json: {
        ...data,
        status: 'error',
        errors: [
          ...(data.errors || []),
          'Failed to parse tests response: ' + e.message
        ],
        rawLLMOutput: response
      }
    }
  ];
}

const fs = require('fs');
const path = require('path');

const data = $input.first().json;
const tests = data.testsData?.tests || [];

const repoDir = path.resolve(data.repoDir);
const written = [];

for (const test of tests) {
  if (!test.filePath || !test.content) continue;

  const resolved = path.resolve(repoDir, test.filePath);

  if (!resolved.startsWith(repoDir + path.sep)) {
    return [{
      json: {
        ...data,
        status: 'error',
        errors: [
          ...data.errors,
          `Path traversal blocked: ${test.filePath}`
        ]
      }
    }];
  }

  fs.mkdirSync(path.dirname(resolved), { recursive: true });
  fs.writeFileSync(resolved, test.content, 'utf8');

  written.push(test.filePath);
}

return [{
  json: {
    ...data,
    testsWritten: written,
    status: 'tests_written'
  }
}];

const data = $input.first().json;
const plan = data.plan;

const filesToCreate = JSON.stringify(plan.files?.create || [], null, 2);
const filesToModify = JSON.stringify(plan.files?.modify || [], null, 2);
const doNotTouch = JSON.stringify(plan.files?.doNotTouch || [], null, 2);

const patterns = (plan.repoContext?.existingPatternsToFollow || []).join('\n');
const antiPatterns = (plan.repoContext?.knownAntiPatternsToAvoid || []).join('\n');

const tests = JSON.stringify(data.testsData || { tests: [] }, null, 2);
const contextBundle = data.contextBundle || '';

const llmPrompt =
`You are the LogiTruck Factory implementation generator.

Return ONLY valid JSON.
Do not use markdown.
Do not use code fences.
Do not explain anything.

Generate implementation files for this feature.

LOGITRUCK FACTORY CONTEXT:
${contextBundle}

IMPLEMENTATION PLAN:
${JSON.stringify(plan, null, 2)}

GENERATED TESTS — make these pass:
${tests}

FILES TO CREATE:
${filesToCreate}

FILES TO MODIFY:
${filesToModify}

DO NOT TOUCH:
${doNotTouch}

EXISTING PATTERNS TO FOLLOW:
${patterns || 'none specified'}

ANTI-PATTERNS TO AVOID:
${antiPatterns || 'none specified'}

RULES:
- Follow LogiTruck architecture patterns from the context bundle.
- Follow the selected archetype.
- Follow the selected building blocks.
- Reuse existing patterns from repoContext.
- Avoid known anti-patterns from repoContext.
- Avoid new dependencies unless the plan explicitly allows them.
- Use explicit TypeScript input and return types.
- Do not use "any" types.
- No hidden Firebase/network/native calls in utilities.
- This is a sandbox integration candidate only.
- Generate only files requested in FILES TO CREATE or FILES TO MODIFY.
- Do not modify protected files.
- Generated tests must pass.

Output exactly this JSON shape:
{
  "files": [
    {
      "filePath": "src/utils/example.ts",
      "content": "full implementation file content"
    }
  ]
}`;

return [
  {
    json: {
      ...data,
      llmPrompt,
      status: 'implementation_prompt_built'
    }
  }
];

const response = $input.first().json;
const data = $('Write Tests').first().json;

const source = response.output || response;

let impl = {
  files: source.files || []
};

impl.files = impl.files.map(file => ({
  ...file,
  content: file.content || Buffer.from(file.contentBase64 || '', 'base64').toString('utf8')
}));

return [{
  json: {
    ...data,
    implData: impl,
    status: 'implementation_generated'
  }
}];

const fs = require('fs');
const path = require('path');
const data = $input.first().json;
const files = (data.implData && data.implData.files) || [];
const doNotTouch = (data.plan.files && data.plan.files.doNotTouch) || [];
const repoDir = path.resolve(data.repoDir);
const written = [];
for (const file of files) {
  if (!file.filePath || !file.content) continue;
  if (doNotTouch.some(function(p) { return file.filePath.includes(p); })) {
    return [{ json: { ...data, status: 'error', errors: [...data.errors, 'Attempted to write protected file: ' + file.filePath] } }];
  }
  const resolved = path.resolve(repoDir, file.filePath);
  if (!resolved.startsWith(repoDir + path.sep) && resolved !== repoDir) {
    return [{ json: { ...data, status: 'error', errors: [...data.errors, 'Path traversal blocked: ' + file.filePath] } }];
  }
  fs.mkdirSync(path.dirname(resolved), { recursive: true });
  fs.writeFileSync(resolved, file.content, 'utf8');
  written.push(file.filePath);
}
return [{ json: { ...data, filesWritten: written, status: 'files_written' } }];

const cmd = $input.first().json;
const data = $('Write Files').first().json;

const output = `STDOUT:\n${cmd.stdout || ''}\n\nSTDERR:\n${cmd.stderr || ''}`;

const match = output.match(/FACTORY_EXIT_CODE=(\d+)/);
const factoryExitCode = match ? Number(match[1]) : 1;

const passed = factoryExitCode === 0;

return [
  {
    json: {
      ...data,
      validationOutput: output,
      validationExitCode: factoryExitCode,
      validationPassed: passed,
      status: passed ? 'validation_passed' : 'validation_failed'
    }
  }
];

const data = $input.first().json;

const filesWritten = JSON.stringify(
  data.filesWritten || [],
  null,
  2
);

const testsWritten = JSON.stringify(
  data.testsWritten || [],
  null,
  2
);

const contextBundle = data.contextBundle || '';

const llmPrompt =
`You are the LogiTruck Factory failure analyzer.

Return ONLY valid JSON.
Do not use markdown.
Do not use code fences.
Do not explain anything.

Analyze this validation failure and classify it.

LOGITRUCK FACTORY CONTEXT:
${contextBundle}

VALIDATION OUTPUT:
${data.validationOutput || ''}

FILES WRITTEN:
${filesWritten}

TESTS WRITTEN:
${testsWritten}

RETRY COUNT:
${data.retryCount} / ${data.maxRetries}

SAFE TO RETRY:
- TypeScript errors
- Missing imports
- Failing isolated tests
- Wrong file paths
- Mock setup errors
- Formatting issues
- Simple logic mismatches
- Invalid exports
- Jest expectation mismatches
- Firebase mock mismatches
- Async test timing issues

MUST ESCALATE:
- Native build failure
- Dependency conflict
- Expo plugin issue
- Stripe/payment production errors
- Firestore security rules violations
- AI runtime orchestration errors
- Unknown runtime errors
- Architectural violations
- Dangerous filesystem writes

RULES:
- Respect LogiTruck architecture patterns.
- Respect archetype restrictions.
- Respect building block constraints.
- Prefer retry for isolated implementation mistakes.
- Escalate only when the issue is structural or unsafe.
- Be concise and deterministic.

Output exactly this JSON shape:
{
  "retryAllowed": true,
  "failureType": "typescript | missing-import | failing-test | path-error | mock-error | formatting | native-build | dependency-conflict | architectural-violation | unknown",
  "rootCause": "short root cause",
  "patchInstructions": "concise patch instructions"
}`;

return [
  {
    json: {
      ...data,
      llmPrompt,
      status: 'failure_analysis_prompt_built'
    }
  }
];

const response = $input.first().json;
const data = $('Parse Validation Result').first().json;

let analysis = {
  retryAllowed: false,
  failureType: 'unknown',
  rootCause: 'Could not parse analysis',
  patchInstructions: ''
};

try {

  const raw =
    response.text ||
    response.output ||
    response.response ||
    '{}';

  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  analysis = JSON.parse(cleaned);

} catch (e) {

  analysis.rootCause =
    'Parse error: ' + e.message;

  analysis.rawLLMOutput = response;
}

const retryAllowed =
  analysis.retryAllowed === true &&
  data.retryCount < data.maxRetries;

return [
  {
    json: {
      ...data,
      failureAnalysis: analysis,
      retryAllowed,
      status: 'failure_analyzed'
    }
  }
];

const data = $input.first().json;

const llmPrompt =
`You are the LogiTruck Factory patch generator.

Return ONLY valid JSON.
Do not use markdown.
Do not use code fences.
Do not explain anything.

Generate patches to fix these validation errors.

VALIDATION OUTPUT:
${data.validationOutput || ''}

FAILURE ANALYSIS:
${JSON.stringify(data.failureAnalysis || {}, null, 2)}

IMPLEMENTATION PLAN:
${JSON.stringify(data.plan || {}, null, 2)}

FILES WRITTEN:
${JSON.stringify(data.filesWritten || [], null, 2)}

TESTS WRITTEN:
${JSON.stringify(data.testsWritten || [], null, 2)}

DO NOT TOUCH:
${JSON.stringify(data.plan?.files?.doNotTouch || [], null, 2)}

RULES:
- Only fix what is broken.
- Do not introduce new dependencies.
- Return COMPLETE file contents for each patched file.
- Do not return diffs.
- Match the original implementation intent.
- Only patch files that already exist in filesWritten/testsWritten unless absolutely required.

Output exactly this JSON shape:
{
  "patches": [
    {
      "filePath": "src/utils/example.ts",
      "content": "full patched file content"
    }
  ],
  "reason": "short explanation of what was fixed"
}`;

return [
  {
    json: {
      ...data,
      llmPrompt
    }
  }
];

const response = $input.first().json;
const data = $('Parse Failure Analysis').first().json;

let patch = {
  patches: [],
  reason: 'No patches generated'
};

try {

  const raw =
    response.text ||
    response.output ||
    response.response ||
    '{}';

  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  patch = JSON.parse(cleaned);

  if (!Array.isArray(patch.patches)) {
    patch = {
      patches: [],
      reason: 'Invalid patch format'
    };
  }

} catch (e) {

  patch = {
    patches: [],
    reason: 'Parse error: ' + e.message,
    rawLLMOutput: response
  };
}

return [
  {
    json: {
      ...data,
      patchData: patch,
      status: 'patch_generated'
    }
  }
];

const fs = require('fs');
const path = require('path');
const data = $input.first().json;
const patches = (data.patchData && data.patchData.patches) || [];
const doNotTouch = (data.plan.files && data.plan.files.doNotTouch) || [];
const repoDir = path.resolve(data.repoDir);
const patchedFiles = [];
for (const patch of patches) {
  if (!patch.filePath || !patch.content) continue;
  if (doNotTouch.some(function(p) { return patch.filePath.includes(p); })) continue;
  const resolved = path.resolve(repoDir, patch.filePath);
  if (!resolved.startsWith(repoDir + path.sep) && resolved !== repoDir) continue;
  fs.mkdirSync(path.dirname(resolved), { recursive: true });
  fs.writeFileSync(resolved, patch.content, 'utf8');
  patchedFiles.push(patch.filePath);
}
const retryEntry = {
  attempt: data.retryCount + 1,
  failureType: data.failureAnalysis && data.failureAnalysis.failureType,
  rootCause: data.failureAnalysis && data.failureAnalysis.rootCause,
  patchedFiles,
  reason: data.patchData && data.patchData.reason
};
return [{ json: { ...data, retryCount: data.retryCount + 1, retryHistory: [...data.retryHistory, retryEntry], status: 'patch_applied' } }];

const cmd = $input.first().json;
const data = $('Apply Patch').first().json;

const output =
  'VALIDATION RETRY ATTEMPT ' + data.retryCount +
  '\n\nSTDOUT:\n' + (cmd.stdout || '') +
  '\n\nSTDERR:\n' + (cmd.stderr || '');

const match = output.match(/FACTORY_EXIT_CODE=(\d+)/);
const factoryExitCode = match ? Number(match[1]) : 1;

const passed = factoryExitCode === 0;

return [
  {
    json: {
      ...data,
      validationOutput: output,
      validationExitCode: factoryExitCode,
      validationPassed: passed,
      status: passed ? 'retry_passed' : 'retry_failed'
    }
  }
];

const fs = require('fs');
const data = $input.first().json;
const h = data.handoffPath;
fs.mkdirSync(h + '/generated-files', { recursive: true });
fs.mkdirSync(h + '/tests', { recursive: true });

fs.writeFileSync(h + '/IMPLEMENTATION_PLAN.json', JSON.stringify(data.plan, null, 2), 'utf8');
fs.writeFileSync(h + '/validation-output.txt', data.validationOutput || 'No validation output.', 'utf8');

const retrySummary = data.retryHistory && data.retryHistory.length
  ? '# Retry Summary\n\nTotal Retries: ' + data.retryCount + '\n\n' + data.retryHistory.map(function(r, i) {
      return '## Attempt ' + (i+1) + '\n- Failure Type: ' + r.failureType + '\n- Root Cause: ' + r.rootCause + '\n- Patched: ' + ((r.patchedFiles || []).join(', ') || 'none') + '\n- Reason: ' + r.reason;
    }).join('\n\n')
  : '# Retry Summary\n\nNo retries performed.';
fs.writeFileSync(h + '/retry-summary.md', retrySummary, 'utf8');

const riskNotes = '# Risk Notes\n\n- Feature: ' + data.featureName + '\n- Archetype: ' + data.featureArchetype + '\n- Execution Level: ' + data.executionLevel + '\n- Risk Level: ' + data.riskLevel + '\n- Validation Passed: ' + data.validationPassed + '\n- Retries: ' + data.retryCount + ' / ' + data.maxRetries + '\n\n## Errors\n' + (data.errors && data.errors.length ? data.errors.map(function(e) { return '- ' + e; }).join('\n') : 'None');
fs.writeFileSync(h + '/risk-notes.md', riskNotes, 'utf8');

const plan = data.plan;
const steps = (plan.claudeCodeIntegrationPlan && plan.claudeCodeIntegrationPlan.steps) || (plan.claudeCodeHandoff && plan.claudeCodeHandoff.tasks) || ['1. Review generated files', '2. Apply to production repo', '3. Run full test suite', '4. Validate runtime behavior', '5. Commit if all checks pass'];
const claudeSteps = '# Claude Code Integration Steps\n\n' + steps.map(function(s,i) { return (i+1) + '. ' + s; }).join('\n') + '\n\n## Files Generated (sandbox only)\n' + ((data.filesWritten || []).map(function(f) { return '- ' + f; }).join('\n') || 'None') + '\n\n## Tests Generated (sandbox only)\n' + ((data.testsWritten || []).map(function(f) { return '- ' + f; }).join('\n') || 'None') + '\n\n## Validation: ' + (data.validationPassed ? 'PASSED' : 'FAILED') + '\n\n> IMPORTANT: Factory output is a sandbox candidate only. Claude Code owns integration and production commit.';
fs.writeFileSync(h + '/claude-integration-steps.md', claudeSteps, 'utf8');

const rollbackSteps = (plan.rollbackPlan && plan.rollbackPlan.steps && plan.rollbackPlan.steps.length)
  ? plan.rollbackPlan.steps.map(function(s,i) { return (i+1) + '. ' + s; }).join('\n')
  : '1. Delete sandbox directory — no production changes were made.\n   Path: ' + data.workDir;
fs.writeFileSync(h + '/rollback-plan.md', '# Rollback Plan\n\n' + rollbackSteps, 'utf8');

let finalStatus = 'ready';
if (!data.validationPassed && data.retryCount > 0) finalStatus = 'needs_fix';
if (!data.validationPassed && data.retryAllowed === false) finalStatus = 'escalated';
if (data.status === 'failure_analyzed' && !data.retryAllowed) finalStatus = 'escalated';

const manifest = {
  featureName: data.featureName,
  featureArchetype: data.featureArchetype,
  executionLevel: data.executionLevel,
  riskLevel: data.riskLevel,
  status: finalStatus,
  filesWritten: data.filesWritten || [],
  testsWritten: data.testsWritten || [],
  validationPassed: data.validationPassed || false,
  retryCount: data.retryCount,
  handoffPath: h,
  timestamp: new Date().toISOString()
};
fs.writeFileSync(h + '/manifest.json', JSON.stringify(manifest, null, 2), 'utf8');
return [{ json: { ...data, finalStatus, manifest, status: 'handoff_packaged' } }];
